// --- CONFIGURATION ---
const FIELDS_TO_PROCESS = ['Editor', 'Video Type', 'Month']; 
const FEEDBACK_LINK_FIELD_NAME = 'Primary Editor Feedback link'; // The name of the field where you want the link stored
const BASE_FEEDBACK_URL = 'https://script.google.com/macros/s/AKfycbzJ_dnlzeoFMnqdDlOL1YZ8x8SE3bxCWLFQiXZAUhlDJCuuRbSKwmEZrIS-0szuzmN7Qw/exec';
// ---------------------

return items.map(item => {
  const task = item.json;
  const customFieldMap = {};
  let feedbackFieldId = null;

  // 1. Process Custom Fields
  if (task.custom_fields && Array.isArray(task.custom_fields)) {
    // Find the specific ID for the Feedback Link field for automation purposes
    const targetField = task.custom_fields.find(f => f.name === FEEDBACK_LINK_FIELD_NAME);
    if (targetField) feedbackFieldId = targetField.id;

    FIELDS_TO_PROCESS.forEach(targetName => {
      const field = task.custom_fields.find(f => f.name === targetName);
      if (!field || field.value === undefined || field.value === null) {
        customFieldMap[targetName] = "N/A";
        return;
      }

      const options = field.type_config?.options;
      const val = field.value;

      if (options) {
        if (Array.isArray(val)) {
          customFieldMap[targetName] = val
            .map(id => options.find(o => o.id === id || o.orderindex == id))
            .filter(o => o).map(o => o.label || o.name).join(', ');
        } else {
          const opt = options.find(o => o.id === val || o.orderindex == val);
          customFieldMap[targetName] = opt ? (opt.label || opt.name) : val;
        }
      } else {
        customFieldMap[targetName] = val;
      }
    });
  }

  // 2. Helper to format Dates
  const formatDate = (timestamp) => {
    if (!timestamp) return "";
    return new Date(parseInt(timestamp)).toISOString().split('T')[0];
  };

  // 3. Generate Encoded Feedback Link
  const editor = customFieldMap['Editor'] || "";
  const taskName = task.name || "";
  const taskLink = task.url || "";
  const taskId = task.id || "";
  const endDate = formatDate(task.date_done || task.due_date);

  const feedbackLink = `${BASE_FEEDBACK_URL}?editor=${encodeURIComponent(editor)}&task=${encodeURIComponent(taskName)}&link=${encodeURIComponent(taskLink)}&id=${encodeURIComponent(taskId)}&enddate=${encodeURIComponent(endDate)}`;

  // 4. Final JSON Construction
  return {
    json: {
      task_id: taskId,
      task_name: taskName,
      task_url: taskLink,
      client_name: task.list ? task.list.name : 'N/A',
      space_name: task.space ? task.space.name : 'N/A',
      fetched_updated_status: task.status ? task.status.status : 'N/A',
      date_created: formatDate(task.date_created),
      last_updated: formatDate(task.date_updated),
      date_completed: formatDate(task.date_closed),
      video_type: customFieldMap['Video Type'],
      video_month: customFieldMap['Month'],
      primary_editor: editor,
      // The generated link for your Google Sheet
      primary_editor_feedback_form_link: feedbackLink,
      // The unique ClickUp ID for the Feedback Link custom field (useful for n8n Update Task node)
      feedback_field_id: feedbackFieldId
    }
  };
});

